     1→import { randomUUID } from "node:crypto";
     2→
     3→import { loadConfigRouteTag } from "./accounts.js";
     4→import { logger } from "../util/logger.js";
     5→import { redactToken } from "../util/redact.js";
     6→
     7→type ActiveLogin = {
     8→  sessionKey: string;
     9→  id: string;
    10→  qrcode: string;
    11→  qrcodeUrl: string;
    12→  startedAt: number;
    13→  botToken?: string;
    14→  status?: "wait" | "scaned" | "confirmed" | "expired";
    15→  error?: string;
    16→};
    17→
    18→const ACTIVE_LOGIN_TTL_MS = 5 * 60_000;
    19→/** Client-side timeout for the long-poll get_qrcode_status request. */
    20→const QR_LONG_POLL_TIMEOUT_MS = 35_000;
    21→
    22→/** Default `bot_type` for ilink get_bot_qrcode / get_qrcode_status (this channel build). */
    23→export const DEFAULT_ILINK_BOT_TYPE = "3";
    24→
    25→const activeLogins = new Map<string, ActiveLogin>();
    26→
    27→interface QRCodeResponse {
    28→  qrcode: string;
    29→  qrcode_img_content: string;
    30→}
    31→
    32→interface StatusResponse {
    33→  status: "wait" | "scaned" | "confirmed" | "expired";
    34→  bot_token?: string;
    35→  ilink_bot_id?: string;
    36→  baseurl?: string;
    37→  /** The user ID of the person who scanned the QR code. */
    38→  ilink_user_id?: string;
    39→}
    40→
    41→function isLoginFresh(login: ActiveLogin): boolean {
    42→  return Date.now() - login.startedAt < ACTIVE_LOGIN_TTL_MS;
    43→}
    44→
    45→/** Remove all expired entries from the activeLogins map to prevent memory leaks. */
    46→function purgeExpiredLogins(): void {
    47→  for (const [id, login] of activeLogins) {
    48→    if (!isLoginFresh(login)) {
    49→      activeLogins.delete(id);
    50→    }
    51→  }
    52→}
    53→
    54→async function fetchQRCode(apiBaseUrl: string, botType: string): Promise<QRCodeResponse> {
    55→  const base = apiBaseUrl.endsWith("/") ? apiBaseUrl : `${apiBaseUrl}/`;
    56→  const url = new URL(`ilink/bot/get_bot_qrcode?bot_type=${encodeURIComponent(botType)}`, base);
    57→  logger.info(`Fetching QR code from: ${url.toString()}`);
    58→
    59→  const headers: Record<string, string> = {};
    60→  const routeTag = loadConfigRouteTag();
    61→  if (routeTag) {
    62→    headers.SKRouteTag = routeTag;
    63→  }
    64→
    65→  const response = await fetch(url.toString(), { headers });
    66→  if (!response.ok) {
    67→    const body = await response.text().catch(() => "(unreadable)");
    68→    logger.error(`QR code fetch failed: ${response.status} ${response.statusText} body=${body}`);
    69→    throw new Error(`Failed to fetch QR code: ${response.status} ${response.statusText}`);
    70→  }
    71→  return await response.json();
    72→}
    73→
    74→async function pollQRStatus(apiBaseUrl: string, qrcode: string): Promise<StatusResponse> {
    75→  const base = apiBaseUrl.endsWith("/") ? apiBaseUrl : `${apiBaseUrl}/`;
    76→  const url = new URL(`ilink/bot/get_qrcode_status?qrcode=${encodeURIComponent(qrcode)}`, base);
    77→  logger.debug(`Long-poll QR status from: ${url.toString()}`);
    78→
    79→  const headers: Record<string, string> = {
    80→    "iLink-App-ClientVersion": "1",
    81→  };
    82→  const routeTag = loadConfigRouteTag();
    83→  if (routeTag) {
    84→    headers.SKRouteTag = routeTag;
    85→  }
    86→
    87→  const controller = new AbortController();
    88→  const timer = setTimeout(() => controller.abort(), QR_LONG_POLL_TIMEOUT_MS);
    89→  try {
    90→    const response = await fetch(url.toString(), { headers, signal: controller.signal });
    91→    clearTimeout(timer);
    92→    logger.debug(`pollQRStatus: HTTP ${response.status}, reading body...`);
    93→    const rawText = await response.text();
    94→    logger.debug(`pollQRStatus: body=${rawText.substring(0, 200)}`);
    95→    if (!response.ok) {
    96→      logger.error(`QR status poll failed: ${response.status} ${response.statusText} body=${rawText}`);
    97→      throw new Error(`Failed to poll QR status: ${response.status} ${response.statusText}`);
    98→    }
    99→    return JSON.parse(rawText) as StatusResponse;
   100→  } catch (err) {
   101→    clearTimeout(timer);
   102→    if (err instanceof Error && err.name === "AbortError") {
   103→      logger.debug(`pollQRStatus: client-side timeout after ${QR_LONG_POLL_TIMEOUT_MS}ms, returning wait`);
   104→      return { status: "wait" };
   105→    }
   106→    throw err;
   107→  }
   108→}
   109→
   110→export type WeixinQrStartResult = {
   111→  qrcodeUrl?: string;
   112→  message: string;
   113→  sessionKey: string;
   114→};
   115→
   116→export type WeixinQrWaitResult = {
   117→  connected: boolean;
   118→  botToken?: string;
   119→  accountId?: string;
   120→  baseUrl?: string;
   121→  /** The user ID of the person who scanned the QR code; add to allowFrom. */
   122→  userId?: string;
   123→  message: string;
   124→};
   125→
   126→export async function startWeixinLoginWithQr(opts: {
   127→  verbose?: boolean;
   128→  timeoutMs?: number;
   129→  force?: boolean;
   130→  accountId?: string;
   131→  apiBaseUrl: string;
   132→  botType?: string;
   133→}): Promise<WeixinQrStartResult> {
   134→  const sessionKey = opts.accountId || randomUUID();
   135→
   136→  purgeExpiredLogins();
   137→
   138→  const existing = activeLogins.get(sessionKey);
   139→  if (!opts.force && existing && isLoginFresh(existing) && existing.qrcodeUrl) {
   140→    return {
   141→      qrcodeUrl: existing.qrcodeUrl,
   142→      message: "二维码已就绪，请使用微信扫描。",
   143→      sessionKey,
   144→    };
   145→  }
   146→
   147→  try {
   148→    const botType = opts.botType || DEFAULT_ILINK_BOT_TYPE;
   149→    logger.info(`Starting Weixin login with bot_type=${botType}`);
   150→
   151→    if (!opts.apiBaseUrl) {
   152→      return {
   153→        message:
   154→          "No baseUrl configured. Add channels.openclaw-weixin.baseUrl to your config before logging in.",
   155→        sessionKey,
   156→      };
   157→    }
   158→
   159→    const qrResponse = await fetchQRCode(opts.apiBaseUrl, botType);
   160→    logger.info(
   161→      `QR code received, qrcode=${redactToken(qrResponse.qrcode)} imgContentLen=${qrResponse.qrcode_img_content?.length ?? 0}`,
   162→    );
   163→    logger.info(`二维码链接: ${qrResponse.qrcode_img_content}`);
   164→
   165→    const login: ActiveLogin = {
   166→      sessionKey,
   167→      id: randomUUID(),
   168→      qrcode: qrResponse.qrcode,
   169→      qrcodeUrl: qrResponse.qrcode_img_content,
   170→      startedAt: Date.now(),
   171→    };
   172→
   173→    activeLogins.set(sessionKey, login);
   174→
   175→    return {
   176→      qrcodeUrl: qrResponse.qrcode_img_content,
   177→      message: "使用微信扫描以下二维码，以完成连接。",
   178→      sessionKey,
   179→    };
   180→  } catch (err) {
   181→    logger.error(`Failed to start Weixin login: ${String(err)}`);
   182→    return {
   183→      message: `Failed to start login: ${String(err)}`,
   184→      sessionKey,
   185→    };
   186→  }
   187→}
   188→
   189→const MAX_QR_REFRESH_COUNT = 3;
   190→
   191→export async function waitForWeixinLogin(opts: {
   192→  timeoutMs?: number;
   193→  verbose?: boolean;
   194→  sessionKey: string;
   195→  apiBaseUrl: string;
   196→  botType?: string;
   197→}): Promise<WeixinQrWaitResult> {
   198→  let activeLogin = activeLogins.get(opts.sessionKey);
   199→
   200→  if (!activeLogin) {
   201→    logger.warn(`waitForWeixinLogin: no active login sessionKey=${opts.sessionKey}`);
   202→    return {
   203→      connected: false,
   204→      message: "当前没有进行中的登录，请先发起登录。",
   205→    };
   206→  }
   207→
   208→  if (!isLoginFresh(activeLogin)) {
   209→    logger.warn(`waitForWeixinLogin: login QR expired sessionKey=${opts.sessionKey}`);
   210→    activeLogins.delete(opts.sessionKey);
   211→    return {
   212→      connected: false,
   213→      message: "二维码已过期，请重新生成。",
   214→    };
   215→  }
   216→
   217→  const timeoutMs = Math.max(opts.timeoutMs ?? 480_000, 1000);
   218→  const deadline = Date.now() + timeoutMs;
   219→  let scannedPrinted = false;
   220→  let qrRefreshCount = 1;
   221→
   222→  logger.info("Starting to poll QR code status...");
   223→
   224→  while (Date.now() < deadline) {
   225→    try {
   226→      const statusResponse = await pollQRStatus(opts.apiBaseUrl, activeLogin.qrcode);
   227→      logger.debug(`pollQRStatus: status=${statusResponse.status} hasBotToken=${Boolean(statusResponse.bot_token)} hasBotId=${Boolean(statusResponse.ilink_bot_id)}`);
   228→      activeLogin.status = statusResponse.status;
   229→
   230→      switch (statusResponse.status) {
   231→        case "wait":
   232→          if (opts.verbose) {
   233→            process.stdout.write(".");
   234→          }
   235→          break;
   236→        case "scaned":
   237→          if (!scannedPrinted) {
   238→            process.stdout.write("\n👀 已扫码，在微信继续操作...\n");
   239→            scannedPrinted = true;
   240→          }
   241→          break;
   242→        case "expired": {
   243→          qrRefreshCount++;
   244→          if (qrRefreshCount > MAX_QR_REFRESH_COUNT) {
   245→            logger.warn(
