const { spawn } = require('child_process');
const fs = require('fs');

const outputFile = '/tmp/wechat_qr_url.txt';
const logFile = '/tmp/wechat_login_full.log';

// 清空之前的文件
fs.writeFileSync(outputFile, '');

const child = spawn('openclaw', ['channels', 'login', '--channel', 'openclaw-weixin'], {
  stdio: ['ignore', 'pipe', 'pipe']
});

child.stdout.on('data', (data) => {
  const output = data.toString();
  console.log(output);

  // 查找二维码 URL
  const urlMatch = output.match(/https?:\/\/[^\s\u{1F300}-\u{1F9FF}]+/u);
  if (urlMatch) {
    const url = urlMatch[0].trim();
    fs.appendFileSync(outputFile, url + '\n');
    console.log('\n✅ 找到二维码 URL:', url);

    // 在浏览器中打开
    setTimeout(() => {
      spawn('cmd', ['/c', 'start', '', url], { detached: true });
    }, 1000);
  }
});

child.stderr.on('data', (data) => {
  const error = data.toString();
  console.error(error);
  fs.appendFileSync(logFile, '[ERROR] ' + error);
});

// 10分钟后超时
setTimeout(() => {
  child.kill();
  process.exit(0);
}, 10 * 60 * 1000);

