const https = require('https');

async function getQRCode() {
  const url = 'https://ilinkai.weixin.qq.com/ilink/bot/get_bot_qrcode?bot_type=3';

  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        try {
          const result = JSON.parse(data);
          console.log('\n二维码内容 (qrcode):', result.qrcode);
          console.log('\n二维码图片 URL:');
          console.log(result.qrcode_img_content);
          console.log('\n正在打开浏览器...');

          // 在浏览器中打开
          const { spawn } = require('child_process');
          spawn('cmd', ['/c', 'start', '', result.qrcode_img_content], { detached: true });

          resolve(result);
        } catch (e) {
          reject(e);
        }
      });
    }).on('error', (e) => {
      reject(e);
    });
  });
}

getQRCode().catch(console.error);

